package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.PatientServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/admin/patients/create")public class PatientCreateServlet extends HttpServlet{private final PatientService service;public PatientCreateServlet(){this(new PatientServiceImpl());}public PatientCreateServlet(PatientService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PatientForm f=new PatientForm();f.setStatus("ACTIVE");f.setBloodGroup("UNKNOWN");show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setCharacterEncoding("UTF-8");PatientForm f=Form.patient(q,null);ServiceResult<Long>x=service.createPatient(f,RequestUtil.buildAuditContext(q));Form.clearPasswords(f);if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/patients?message=created");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,PatientForm f)throws ServletException,IOException{q.setAttribute("formMode","CREATE");q.setAttribute("patientForm",f);q.setAttribute("linkedAccount",false);q.getRequestDispatcher("/WEB-INF/views/admin/patients/form.jsp").forward(q,r);}}
